   /* create sample dataset */
   data orders;
     input order_id order_date : date9. order_total;
     format order_date date9.;
     datalines;
1 01jan2022 100
2 02jan2022 200
3 03jan2022 300
4 04jan2022 400
5 05jan2022 500
;
   run;

   /* use RETAIN to calculate running total and lag pattern */
   data orders_with_running_total;
     retain cumulative_total 0;
     set orders;
     /* calculate running total */
     cumulative_total + order_total;
     lag_order_total = lag(order_total);
     /* keep original variables and add new ones */
     output;
   run;

   /* print the resulting dataset */
   proc print data=orders_with_running_total;
     var order_id order_date order_total cumulative_total lag_order_total;
   run;

/* define master dataset */
data orders;
  input order_id order_date;
  datalines;
  1 20220101
  2 20220115
  3 20220201
  ;
run;

/* define transactional dataset */
data order_items;
  input order_id item_id item_name;
  datalines;
  1 101 itemA
  1 102 itemB
  2 201 itemC
  2 202 itemD
  3 301 itemE
  ;
run;

/* merge and update using MERGE_BY and MERGE_SEMANTICS */
data updated_orders;
  merge orders
        order_items(rename = (order_id = order_id_match));
  by order_id;
  if order_id = order_id_match then do;
    put 'Updating order # ' order_id;
    /* perform update logic here */
    update_order = 1;
  end;
  else do;
    put 'No match found for order # ' order_id;
    update_order = 0;
  end;
  drop order_id_match;
run;

/* print updated orders */
proc print data = updated_orders;
  var order_id order_date update_order;
run;

/* Create sample dataset: employees */
data employees;
   input id name $ department $ salary;
   datalines;
1 John Sales 50000
2 Emma Marketing 60000
3 Michael IT 70000
4 Sarah Sales 55000
5 David Marketing 65000
6 Tom IT 75000
;

/* Create sample dataset: sales */
data sales;
   input id sales_amount;
   datalines;
1 10000
2 20000
3 30000
4 15000
5 25000
6 35000
;

/* Use PROC SQL to analyze data */
proc sql;
/* Select id, name, department, and total sales */
select e.id, e.name, e.department, sum(s.sales_amount) as total_sales
/* Join employees with sales on id */
from employees e
/* Inner join to only include matched records */
inner join sales s
on e.id = s.id
/* Group records by department */
group by e.department
/* Only include departments with total sales > 30000 */
having sum(s.sales_amount) > 30000
;
quit;

/* Create a sample dataset with dates */
data orders;
   format order_date date9. shipment_date date9.;
   order_date = '01jan2020'd;
   shipment_date = '15jan2020'd;
   output;
run;

/* Calculate number of days between order and shipment dates */
data orders;
   set orders;
   days_to_ship = shipment_date - order_date; /* date difference */
run;

/* Use INTCK to count months between order and shipment dates */
data orders;
   set orders;
   months_to_ship = intck('month', order_date, shipment_date); /* count months */
run;

/* Use INTNX to calculate next quarter after order date */
data orders;
   set orders;
   next_quarter = intnx('quarter', order_date, 1); /* next quarter */
run;

/* Use TODAY and MDY to create current date and manipulate month/day */
data _null_;
   current_date = today(); /* get today's date */
   manipulated_date = mdy(12, 31, year(current_date)); /* create date object for Dec 31st of current year */
   put manipulated_date date9.; /* print manipulated date */
run;

/* Extract date part from datetime object */
data orders;
   set orders;
   date_part = datepart(datetime()); /* extract date part from datetime object */
run;

/* define a macro to calculate summary statistics */
%macro summary_stats(data=, var=);
  /* set title */
  title "Summary Statistics for &var";
  /* calculate summary statistics */
  proc means data=&data mean std min max;
    var &var;
  run;
%mend;

/* create sample dataset */\ndata sales;
  input region $ sales;
  datalines;
North 100
North 200
South 50
South 150
East  300
East  250
;

/* call the macro */\n%summary_stats(data=sales, var=sales);

/* Define the dataset */
data patients;
   input id patient_name $ age gender $;
   datalines;
   1 John 25 M
   2 Emma 32 F
   3 Michael 41 M
   4 Sophia 28 F
   5 William 35 M
   6 Olivia 29 F
;

/* Sort the data by age */
proc sort data=patients;
   by age;
run;

/* Use PROC_MEANS to calculate the mean age by gender */
proc means data=patients nwayer;
   class gender;
   var age;
   output out=means_output mean=avg_age;
run;

/* Print the results */
proc print data=means_output;
   var gender avg_age;
run;

